update public.books b
set title = c.title,
    subtitle = c.subtitle,
    description = c.description,
    cover_url = 'https://picsum.photos/seed/' || c.cover_seed || '/480/672',
    tags = case when c.is_interactive then c.tags || array['تعاملی'] else c.tags end,
    metadata = coalesce(b.metadata, '{}'::jsonb) || jsonb_build_object('category', c.category, 'publisher_name', 'انتشارات دانش نو'),
    pages = (
      select jsonb_agg(
        case
          when page_no = 1 and row_no % 4 = 0 then
            jsonb_set(
              page,
              '{blocks}',
              coalesce(page->'blocks', '[]'::jsonb) || jsonb_build_array(
                jsonb_build_object(
                  'type', 'image',
                  'url', 'https://picsum.photos/seed/' || c.cover_seed || '-inside/960/540',
                  'caption', 'تصویری از فضای موضوعی کتاب «' || c.title || '»'
                )
              )
            )
          else page
        end
        order by page_no
      )
      from jsonb_array_elements(b.pages) with ordinality as p(page, page_no)
    ),
    updated_at = now(),
    content_version = b.content_version + 1,
    content_updated_at = now()
from (
  select catalog.*, row_number() over () as row_no
  from catalog
) c
where b.title = c.old_title;
